120→    private fun initializeUiFromBundle(bundle: Bundle) {
121→        setContentView(R.layout.card_browser_appearance)
122→
123→        questionEditText = findViewById(R.id.question_format)
124→        questionEditText.setText(bundle.getString(INTENT_QUESTION_FORMAT))
125→
126→        answerEditText = findViewById(R.id.answer_format)
127→        answerEditText.setText(bundle.getString(INTENT_ANSWER_FORMAT))
128→
129→        enableToolbar()
