 87→        return new AnkiDroidJS({ developer, version });
 88→    }
 89→
 90→    handleRequest = async (endpoint, data) => {
 91→        const url = `/jsapi/${endpoint}`;
 92→        try {
 93→            const response = await fetch(url, {
 94→                method: "POST",
 95→                headers: {
 96→                    "Content-Type": "application/json",
 97→                },
 98→                body: JSON.stringify({
 99→                    developer: this.developer,
100→                    version: this.version,
101→                    data,
102→                }),
103→            });
104→
105→            if (!response.ok) {
106→                throw new Error("Failed to make the request");
107→            }
108→
109→            const responseData = await response.text();
110→            if (endpoint.includes("nextTime") || endpoint.includes("deckName")) {
111→                return responseData;
112→            }
113→            return JSON.parse(responseData);
114→        } catch (error) {
115→            console.error("Request error:", error);
116→            throw error;
117→        }
118→    };
119→}
