        var madeChanges = false
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            // Check if it already has a scheme (e.g., http://, file://)
            // We use a simple prefix check to avoid URI parsing issues with special
            // characters like '#' which would be interpreted as fragment identifiers
            if (attrValue.contains("://")) continue

            val path = Paths.get(mediaDir, attrValue).toString()
            val newUri = getFileUri(path)

            elem.attr(attr, newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }"}

