    /**
     * Converts the ordinal (mOrdinal) to a card index.
     * For cloze notes, the ordinal is the ord value (0-based), and we need to find its position
     * in the list of cloze numbers.
     * For non-cloze notes, ordinal equals cardIndex.
     */
    private fun getCardIndexFromOrdinal(col: Collection): Int {
        if (mEditedNotetype == null) return mOrdinal

        if (mEditedNotetype!!.isCloze) {
            // Create a temporary note to get the cloze numbers
            val n = col.newNote(mEditedNotetype!!)
            val fieldValues = getBundleEditFields(mNoteEditorBundle)
            for (i in fieldValues.indices) {
                if (i < n.fields.size) {
                    n.setField(i, fieldValues[i])
                }
            }
            val clozeNumbers = col.clozeNumbersInNote(n)
            // mOrdinal is 0-based (ord), clozeNumbers are 1-based (e.g., [1, 3] for c1, c3)
            val index = clozeNumbers.indexOf(mOrdinal + 1)
            return if (index >= 0) index else 0
        }

        return mOrdinal
    }

