324→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
325→        val noteFields = noteEditorBundle!!.getBundle("editFields")
326→            ?: return mutableListOf()
327→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
328→        // so convert this to a list of strings, with null in place of the invalid fields
329→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
330→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
331→        for (fieldOrd in noteFields.keySet()) {
332→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
333→        }
334→        return mutableListOf(*ret)
335→    }
